{"command": "cd /tmp/sv-81c3982380684ac394e4044dd555a433/advanced-multi-complexity && dotnet package list --format json 2>/dev/null | python3 -c "
import json, sys
data = json.load(sys.stdin)
json.dump(data, open('after-cpm-packages.json','w'), indent=2)

baseline = json.load(open('baseline-packages.json'))
after = data

def get_pkgs(d):
    result = {}
    for p in d.get('projects',[]):
        pname = p['path'].split('/')[-1]
        for fw in p.get('frameworks',[]):
            for pkg in fw.get('topLevelPackages',[]):
                key = (pname, fw['framework'], pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = get_pkgs(baseline)
a = get_pkgs(after)

changes = []
unchanged = []
for key in sorted(set(list(b.keys()) + list(a.keys()))):
    proj, fw, pkg = key
    bv = b.get(key)
    av = a.get(key)
    if bv != av:
        changes.append((proj, fw, pkg, bv or 'N/A', av or 'N/A'))
    else:
        unchanged.append((proj, fw, pkg, av))

print('=== CHANGES ===')
for c in changes:
    print(f'{c[0]} [{c[1]}] {c[2]}: {c[3]} -> {c[4]}')
print()
print('=== UNCHANGED ===')
for u in unchanged:
    print(f'{u[0]} [{u[1]}] {u[2]}: {u[3]}')
"", "description": "Compare baseline vs after packages", "initial_wait": 30}

